/// The type of an editable mako setting (drives the input widget + validation).
#[derive(Debug, Clone, Copy)]
pub enum Kind {
    Int {
        min: i64,
        max: i64,
    },
    Enum(&'static [&'static str]),
    Bool,
    /// Free text (font name, icon path).
    Text,
}

/// One editable global mako setting.
#[derive(Debug, Clone, Copy)]
pub struct Setting {
    /// The mako config key, e.g. `default-timeout`.
    pub key: &'static str,
    pub label: &'static str,
    pub group: &'static str,
    pub kind: Kind,
    /// The stock default (from `core.ini`), shown until the user overrides it.
    pub default: &'static str,
    pub help: &'static str,
}

use Kind::*;

const fn s(
    key: &'static str,
    label: &'static str,
    group: &'static str,
    kind: Kind,
    default: &'static str,
    help: &'static str,
) -> Setting {
    Setting {
        key,
        label,
        group,
        kind,
        default,
        help,
    }
}

